    private static class RetryInterceptor implements Interceptor {
        private final int maxRetries;

        RetryInterceptor(int maxRetries) {
            this.maxRetries = maxRetries;
        }

        @Override
        public Response intercept(Chain chain) throws IOException {
            Request request = chain.request();
            IOException lastException = null;

            for (int attempt = 0; attempt <= maxRetries; attempt++) {
                try {
                    Response response = chain.proceed(request);
                    if (response.isSuccessful() || attempt == maxRetries) {
                        return response;
                    }
                    // Retry on server errors
                    if (response.code() >= 500) {
                        response.close();
                        Log.w(TAG, "Server error " + response.code() + ", retry attempt " + (attempt + 1));
                        sleep(1000L * (attempt + 1));
                        continue;
                    }
                    return response;
                } catch (IOException e) {
                    lastException = e;
                    Log.w(TAG, "Request failed, retry attempt " + (attempt + 1) + ": " + e.getMessage());
                    if (attempt < maxRetries) {
                        sleep(1000L * (attempt + 1));
                    }
                }
            }

            throw lastException != null ? lastException : new IOException("Request failed after " + maxRetries + " retries");
        }

        private void sleep(long millis) {
            try {
                Thread.sleep(millis);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

